   9→/// Log level for the frontend, controlled by SHATTER_LOG_LEVEL env var.
  10→#[derive(Debug, Clone, Copy, PartialEq, Eq, PartialOrd, Ord)]
  11→enum FrontendLogLevel {
  12→    Error = 0,
  13→    Warn = 1,
  14→    Info = 2,
  15→    Debug = 3,
