    let code = r#"
        enum List { Cons(i32, Box<List>), Nil }
        fn f(l: List) {}
    "#;
    let f = analyze_fn(code, "f");
    assert!(matches!(f.params[0].typ, TypeInfo::Union { .. }));
}

