fn enum_not_in_same_file_remains_opaque() {
    let f = analyze_fn("fn f(x: ExternalEnum) {}", "f");
    assert_eq!(
        f.params[0].typ,
        TypeInfo::Opaque {
            label: "ExternalEnum".to_string()
        }
    );
}

