fn generic_param_with_bounds_maps_to_unknown() {
    let f = analyze_fn(
        "fn f<T: std::fmt::Display + Clone>(x: T) {}",
        "f",
    );
    assert_eq!(f.params[0].typ, TypeInfo::Unknown);
}

