        assert_eq!(for_branches.len(), 1);
    }

    #[test]
    fn extracts_try_operator_branch() {
        let f = analyze_fn(
            r#"
            fn f(input: &str) -> Result<i32, String> {
                let n = input.parse::<i32>().map_err(|e| e.to_string())?;
                Ok(n)
            }
            "#,
