    fn groups_multiple_calls_to_same_symbol() {
        let f = analyze_fn(
            r#"
            fn f(x: i32) {
                db::save(x);
                db::save(x + 1);
            }
            "#,
            "f",
        );
        assert_eq!(f.dependencies.len(), 1);
        assert_eq!(f.dependencies[0].call_sites.len(), 2);
    }

    // ── Error handling tests ──

    #[test]
    fn function_not_found_returns_error() {
