fn box_dyn_trait_maps_to_opaque() {
    let code = r#"
        trait Handler { fn handle(&self); }
        fn f(h: Box<dyn Handler>) {}
    "#;
    let f = analyze_fn(code, "f");
    // Box<dyn Handler> → the inner type is a trait object, wrapped in Nullable
    // (since Box maps like Option). The inner should be Opaque.
    match &f.params[0].typ {
        TypeInfo::Nullable { inner } => {
            assert_eq!(
                **inner,
                TypeInfo::Opaque {
                    label: "dyn Handler".to_string()
                }
            );
        }
        other => panic!("expected Nullable(Opaque), got {:?}", other),
    }
}

